import{_ as t,o,c as n,a2 as i}from"./chunks/framework.BaLY0aY1.js";const r="/torch/assets/consent_pipeline.eld2DOXv.svg",s="/torch/assets/consent_pipeline_dark.BiWH3uU4.svg",a="/torch/assets/consent_encounter.CWNE3ShB.svg",d="/torch/assets/consent_encounter_dark.DvYtDuxB.svg",c="/torch/assets/consent_retro.GMo7Rg8N.svg",l="/torch/assets/consent_retro_dark.BGdAoz20.svg",v=JSON.parse('{"title":"Consent Handling in TORCH","description":"","frontmatter":{},"headers":[],"relativePath":"implementation/consent.md","filePath":"implementation/consent.md","lastUpdated":1781263125000}'),p={name:"implementation/consent.md"};function h(u,e,m,g,f,b){return o(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="consent-handling-in-torch" tabindex="-1">Consent Handling in TORCH <a class="header-anchor" href="#consent-handling-in-torch" aria-label="Permalink to &quot;Consent Handling in TORCH&quot;">​</a></h1><p>TORCH implements <strong>privacy-aware consent handling</strong> to ensure that the extracted data strictly complies with patient permissions and applicable regulations.</p><blockquote><p><strong>v1.0.0-beta.1 — FDPG-Project consent scope clarified</strong></p><p>As of this release, TORCH exclusively evaluates the two MII consent provision codes required for FDPG &quot;Zentrale Analyse&quot; (centralised data extraction for researchers):</p><table tabindex="0"><thead><tr><th>Code</th><th>OID</th><th>Role</th></tr></thead><tbody><tr><td>MDAT wissenschaftlich nutzen EU DSGVO NIVEAU</td><td><code>2.16.840.1.113883.3.1937.777.24.5.3.8</code></td><td>Validity gate — today must fall within the provision period</td></tr><tr><td>MDAT erheben</td><td><code>2.16.840.1.113883.3.1937.777.24.5.3.6</code></td><td>Data-extraction window — resources outside this period are excluded</td></tr></tbody></table><p>Both codes must appear <strong>together</strong> in the CRTDL cohort definition; TORCH rejects requests where only one is present. The optional retrospective modifiers (<code>.45</code> / <code>.46</code>) extend <code>.6</code>&#39;s period back to 1900-01-01 when present in the same Consent resource and explicitly requested in the CRTDL.</p><p>All other MII consent codes (BIOMAT, KKDAT, IDAT, etc.) are <strong>silently ignored</strong>.</p></blockquote><hr><h2 id="_1-consent-representation" tabindex="-1">1. Consent Representation <a class="header-anchor" href="#_1-consent-representation" aria-label="Permalink to &quot;1. Consent Representation&quot;">​</a></h2><ul><li>TORCH supports the <a href="https://www.hl7.org/fhir/consent.html" target="_blank" rel="noreferrer">FHIR Consent</a> resource as the canonical way to represent patient consent.</li><li>The MII broad consent model typically represents a signing event as a FHIR Consent resource, with each consented policy code encoded as a sibling provision nested inside a single top-level deny provision. Sites may produce multiple Consent resources per signing event.</li><li>Consent records define: <ul><li><strong>Who</strong> has granted consent</li><li><strong>What</strong> data may be accessed</li><li><strong>Purpose</strong> and permitted actions</li><li><strong>Conditions</strong> or time limits</li></ul></li></ul><hr><h2 id="_2-supported-consent-codes" tabindex="-1">2. Supported Consent Codes <a class="header-anchor" href="#_2-supported-consent-codes" aria-label="Permalink to &quot;2. Supported Consent Codes&quot;">​</a></h2><p>TORCH only processes consent provision codes listed in <a href="https://github.com/medizininformatik-initiative/torch/blob/main/mappings/consent-code-config.json" target="_blank" rel="noreferrer"><code>mappings/consent-code-config.json</code></a>. This file can be edited manually to adjust the supported codes for a deployment. The codes shipped with TORCH represent the recommended MII default for FDPG-Project (Zentrale Analyse) use cases.</p><p>Each entry in the config describes a <strong>prospective code</strong> with:</p><table tabindex="0"><thead><tr><th>Field</th><th>Meaning</th></tr></thead><tbody><tr><td><code>validityGate</code></td><td>If <code>true</code>, today must fall within the patient&#39;s permitted period for this code — patient is excluded if not</td></tr><tr><td><code>required</code></td><td>Other codes that must co-occur with this one in the CRTDL cohort definition</td></tr><tr><td><code>retroModifiers</code></td><td>Optional modifier codes that extend this code&#39;s permitted period backwards to a fixed <code>lookbackDate</code></td></tr></tbody></table><p><strong>Shipped default:</strong></p><table tabindex="0"><thead><tr><th>Code</th><th>OID</th><th>Role</th></tr></thead><tbody><tr><td>MDAT wissenschaftlich nutzen EU DSGVO NIVEAU</td><td><code>2.16.840.1.113883.3.1937.777.24.5.3.8</code></td><td>Validity gate (today-in-period check)</td></tr><tr><td>MDAT erheben</td><td><code>2.16.840.1.113883.3.1937.777.24.5.3.6</code></td><td>Data-extraction window</td></tr><tr><td>MDAT retrospektiv speichern, verarbeiten</td><td><code>2.16.840.1.113883.3.1937.777.24.5.3.45</code></td><td>Retrospective modifier for <code>.6</code> (optional)</td></tr><tr><td>MDAT retrospektiv wissenschaftlich nutzen EU DSGVO NIVEAU</td><td><code>2.16.840.1.113883.3.1937.777.24.5.3.46</code></td><td>Retrospective modifier for <code>.6</code> (optional)</td></tr></tbody></table><p><code>.8</code> and <code>.6</code> are declared as mutually required — both must appear together in the CRTDL cohort definition. Codes not listed in <code>consent-code-config.json</code> are silently ignored.</p><hr><h2 id="_3-consent-evaluation-pipeline" tabindex="-1">3. Consent Evaluation Pipeline <a class="header-anchor" href="#_3-consent-evaluation-pipeline" aria-label="Permalink to &quot;3. Consent Evaluation Pipeline&quot;">​</a></h2><img src="'+r+'" class="diagram-light" alt="Consent evaluation pipeline flowchart"><img src="'+s+'" class="diagram-dark" alt="Consent evaluation pipeline flowchart"><p>Before any data extraction:</p><ol><li><strong>Extract consent codes from CRTDL</strong> — codes are read from the <code>cohortDefinition</code> inclusion criteria. TORCH extracts only the provision codes that are present and ignores their Boolean combination (AND/OR).</li><li><strong>Validate co-occurrence</strong> — for every supported code present, all codes listed in its <code>required</code> field must also be present. If <code>.6</code> appears without <code>.8</code> (or vice-versa), the request is rejected with a <code>ConsentFormatException</code>.</li><li><strong>Filter to supported codes</strong> — only prospective codes defined in <code>consent-code-config.json</code> are retained.</li><li><strong>Fetch from FHIR</strong> — <strong>Active</strong> Consent resources are fetched for the supported codes, plus any retro modifier codes that were explicitly requested in the CRTDL.</li><li><strong>Adjust by Encounter</strong> — for data-period codes (non-gate codes, i.e. <code>.6</code>), the start of each permitted provision is shifted to the start of the earliest overlapping Encounter if that Encounter start is earlier. Gate codes (<code>.8</code>) are never encounter-adjusted by design.</li><li><strong>Apply retrospective modifiers</strong> — within each Consent resource independently: if a permitted <code>.6</code> provision overlaps in time with a permitted retro modifier provision (<code>.45</code>/<code>.46</code>) <strong>in the same resource</strong>, the <code>.6</code> provision&#39;s start is shifted to <code>1900-01-01</code>. Retro modifier denies (<code>.45</code>/<code>.46</code> deny) in the same resource subtract from the retro-extended period before it is recorded. Modifiers and their denies from a different Consent resource have no effect.</li><li><strong>Merge and subtract</strong> — only Consent resources that contain permits for <strong>all</strong> required codes (<code>.6</code> AND <code>.8</code>) contribute permit periods. Deny periods from <strong>any</strong> Consent resource are subtracted from the merged permits, including revocation documents that carry only denies. Retro-extended periods are immune to prospective code denies (<code>.6</code> deny) — only retro modifier denies (<code>.45</code>/<code>.46</code> deny, applied in step 6) can reduce them.</li><li><strong>Gate check</strong> — for each validity-gate code (<code>.8</code>), today must fall within the merged permitted period. If the check fails for any gate code the patient is excluded from the result.</li><li><strong>Intersect data periods</strong> — the allowed periods of all data-period codes (<code>.6</code>) are intersected to produce the patient&#39;s final data-extraction window.</li><li><strong>Enforce during extraction</strong> — resources whose consent data field (as configured in <code>type_to_consent.json</code>) falls outside the consent window are excluded from the result.</li></ol><h3 id="encounter-adjustment" tabindex="-1">Encounter Adjustment <a class="header-anchor" href="#encounter-adjustment" aria-label="Permalink to &quot;Encounter Adjustment&quot;">​</a></h3><p>The diagram below shows two patients — <strong>MII BC1</strong> (encounter adjustment applied) and <strong>MII BC2</strong> (no adjustment) — to illustrate how step 5 shifts the <code>.6</code> provision start.</p><img src="'+a+'" class="diagram-light" alt="Consent timeline showing encounter-based start adjustment"><img src="'+d+'" class="diagram-dark" alt="Consent timeline showing encounter-based start adjustment"><p>In BC1, the <code>.6</code> window is extended back to the start of the overlapping encounter (ENC 1), making additional historical resources (R9–R11) eligible for extraction compared to BC2 where the window starts at <code>bcStart</code>.</p><hr><h2 id="_4-validity-gate-vs-data-extraction-window" tabindex="-1">4. Validity Gate vs. Data-Extraction Window <a class="header-anchor" href="#_4-validity-gate-vs-data-extraction-window" aria-label="Permalink to &quot;4. Validity Gate vs. Data-Extraction Window&quot;">​</a></h2><p><code>.8</code> (MDAT wissenschaftlich nutzen) and <code>.6</code> (MDAT erheben) play distinct roles:</p><table tabindex="0"><thead><tr><th>Code</th><th>Role</th><th>What it controls</th></tr></thead><tbody><tr><td><code>.8</code></td><td>Validity gate</td><td>Is the patient&#39;s consent currently active? Today must be within the period.</td></tr><tr><td><code>.6</code></td><td>Data window</td><td>How far back in time may data be extracted?</td></tr></tbody></table><p>Both must be present in the CRTDL. If <code>.8</code> fails the gate check (e.g. the patient&#39;s consent has expired) the patient is excluded entirely — <code>.6</code> is not evaluated.</p><hr><h2 id="_5-retrospective-modifier-semantics" tabindex="-1">5. Retrospective Modifier Semantics <a class="header-anchor" href="#_5-retrospective-modifier-semantics" aria-label="Permalink to &quot;5. Retrospective Modifier Semantics&quot;">​</a></h2><p>The retrospective modifiers (<code>.45</code>, <code>.46</code>) act as <strong>period extenders</strong> for <code>.6</code>:</p><ul><li>A modifier is only applied if it was explicitly requested in the CRTDL.</li><li>A modifier is only applied when it appears in the <strong>same Consent resource</strong> as the <code>.6</code> provision it extends. A <code>.45</code> permit in resource B does <strong>not</strong> extend a <code>.6</code> permit in resource A.</li><li>A modifier affects a permitted <code>.6</code> provision when their periods <strong>overlap within the same resource</strong>.</li><li>When applied, the <code>.6</code> provision&#39;s start date is replaced with <code>1900-01-01</code>.</li><li>If a patient has no permitted <code>.6</code> provisions in the same resource as the modifier, the modifier has no effect.</li><li>Retro modifier <strong>denies</strong> (<code>.45</code>/<code>.46</code> deny) in the same resource subtract from the retro-extended period.</li><li>Prospective code <strong>denies</strong> (<code>.6</code> deny) do <strong>not</strong> reduce a retro-extended period — only the retro modifier deny can revoke the retroactive grant.</li></ul><p>The diagram below shows the two key cases — with and without a retro modifier deny.</p><img src="'+c+'" class="diagram-light" alt="Retrospective modifier semantics diagram"><img src="'+l+`" class="diagram-dark" alt="Retrospective modifier semantics diagram"><p><strong>Example:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Consent resource A (signed 2020):</span></span>
<span class="line"><span>  .8  2020–2050  permit</span></span>
<span class="line"><span>  .6  2020–2025  permit</span></span>
<span class="line"><span>  .45 2020–2025  permit   ← same resource, overlaps .6 → extends .6 start to 1900-01-01</span></span>
<span class="line"><span>  .45 2000–2009  deny     ← same resource, subtracts [2000-01-01, 2009-12-31] from extended .6</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Consent resource B (revocation, 2023):</span></span>
<span class="line"><span>  .6  2023–2025  deny     ← does NOT reduce the retro-extended .6 from resource A</span></span>
<span class="line"><span>  .45 2023–2025  permit   ← different resource from resource A&#39;s .6 → no effect</span></span></code></pre></div><hr><h2 id="_6-enforcement-in-data-processing" tabindex="-1">6. Enforcement in Data Processing <a class="header-anchor" href="#_6-enforcement-in-data-processing" aria-label="Permalink to &quot;6. Enforcement in Data Processing&quot;">​</a></h2><ul><li>Data outside the patient&#39;s consent window are excluded from the result set.</li><li>All enforcement happens <strong>before</strong> results are packaged into NDJSON bundles.</li></ul><hr><h2 id="_7-integration-with-crtdl" tabindex="-1">7. Integration with CRTDL <a class="header-anchor" href="#_7-integration-with-crtdl" aria-label="Permalink to &quot;7. Integration with CRTDL&quot;">​</a></h2><ul><li>CRTDL definitions reference consent via the <code>cohortDefinition</code> inclusion criteria.</li><li>The consent check uses a specific date field per FHIR resource type. If no field is configured for a resource type, all resources of that type are considered consented (see <a href="https://github.com/medizininformatik-initiative/torch/blob/main/mappings/type_to_consent.json" target="_blank" rel="noreferrer">type_to_consent.json</a>).</li></ul><hr><h2 id="_8-limitations-and-considerations" tabindex="-1">8. Limitations and Considerations <a class="header-anchor" href="#_8-limitations-and-considerations" aria-label="Permalink to &quot;8. Limitations and Considerations&quot;">​</a></h2><ul><li>Within a single consent block in the cohort definition (CCDL), TORCH extracts the individual consent provision codes and ignores their Boolean combination — the co-occurrence and period logic described above is applied instead.</li><li>Consent records must be <strong>up-to-date</strong> and accurately reflect patient permissions.</li><li>Only the codes listed in <code>consent-code-config.json</code> are evaluated — all others are ignored.</li><li>The shipped default config supports the MII FDPG-Project (Zentrale Analyse) consent codes; other use cases may are currently not supported.</li><li>TORCH treats all data in the FHIR server as MDAT (Medizinische Daten).</li><li>TORCH does not consider consent versioning — provision codes are assumed to be unique and to retain the same meaning across all versions of the consent profile.</li></ul><hr><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Consent handling in TORCH is:</p><ul><li><strong>Standards-based</strong> (FHIR Consent, MII KDS profile, MII broad consent structure)</li><li>Per-patient: permits only from Consent resources that carry the complete required package (<code>.6</code> AND <code>.8</code>); denies applied globally; retro modifiers and their denies scoped to the resource they appear in</li><li>Driven by <code>consent-code-config.json</code> — no code changes required for new consent codes that follow the same combination logic as the default set. <strong>This is a fundamental limitation:</strong> TORCH can only handle the validity-gate <ul><li>data-window + retrospective-modifier model hardcoded in its pipeline. New codes that require different combination semantics (e.g. a different gate structure, alternative period logic, or additional provision types) cannot be supported through configuration alone and require code changes.</li></ul></li></ul>`,52)])])}const w=t(p,[["render",h]]);export{v as __pageData,w as default};
